import * as t from "io-ts";
import { StakeIntent } from "./stakeIntent";
import { RecipientEntry } from "./recipientEntry";

/**
 * @title Near Stake Intent
 */
export const NearStakeIntent = t.intersection([
  StakeIntent,
  t.type({
    recipients: t.array(RecipientEntry),
  }),
]);

export type NearStakeIntent = t.TypeOf<typeof NearStakeIntent>;
